local fbStatus = FG:AddLabel("", true)
FG:AddButton({
    Text = "📨 Send",
    Func = function()
        local now = tick()
        if now - lastFeedback < FEEDBACK_COOLDOWN then
            safeSet(fbStatus, string.format("%d초 후에 다시 보낼 수 있습니다.", math.ceil(FEEDBACK_COOLDOWN - (now - lastFeedback))))
            return
        end
        local ftype = tostring((Options.FeedbackType and Options.FeedbackType.Value) or "Suggestion"):lower()
        local msg   = M.trim((Options.FeedbackMsg and Options.FeedbackMsg.Value) or "")
        if msg == "" then safeSet(fbStatus, "메시지가 비어 있습니다."); return end
        if #msg > 500 then safeSet(fbStatus, "메시지가 너무 깁니다 (최대 500자)."); return end
        local low = msg:lower()
        if low:find("http", 1, true) or low:find("discord.gg", 1, true) or low:find("www.", 1, true) or low:find(".gg/", 1, true) then
            safeSet(fbStatus, "링크는 허용되지 않습니다."); return
        end
        safeSet(fbStatus, "전송 중...")
        task.spawn(function()
            local sok, err = M.sendFeedback(ftype, msg, (preCheck and preCheck.session_token) or "")
            if sok then
                lastFeedback = tick()
                safeSet(fbStatus, "✅ 전송 완료. 감사합니다!")
                pcall(function() Options.FeedbackMsg:SetValue("") end)
                Library:Notify({Title = "COMBOWICK", Description = "피드백이 전송되었습니다. 감사합니다!", Time = 3})
            else
                safeSet(fbStatus, ERRMAP[err] or ("전송 실패: " .. tostring(err)))
            end
        end)
    end,
})
