task.spawn(function()
    safeSet(statusLabel, "인증 중...")

    local result = M.withRetry(M.checkSession, M.hwid)

    if result == nil then
        safeSet(statusLabel, "상태: 실패")
        Library:Notify({Title="COMBOWICK", Description="세션 확인에 실패했습니다.", Time=5})

    elseif result.status == "allowed" or result.status == "session_active" then
        if result.disabled then
            safeSet(statusLabel, "⛔ 게임 비활성화")
            safeSet(hintLabel, "여기서는 무료 버전을 사용할 수 없습니다. 키를 받으세요.")
            Library:Notify({Title="COMBOWICK", Description="이 게임에서는 무료 버전이 비활성화되어 있습니다. 키를 사용해 주세요.", Time=6})
            return
        end
        local token = result.session_token
        if type(token) ~= "string" or #token < 20 then
            safeSet(statusLabel, "상태: 실패")
        else
            safeSet(statusLabel, "상태: 인증됨")
            Library:Notify({Title="COMBOWICK", Description="인증되었습니다.", Time=3})
            _G.COMBOWICK_FREE   = true
            _G.COMBOWICK_ACTIVE = true
            local remaining = tonumber(result.remaining) or 0
            task.spawn(function()
                while remaining > 0 do
                    local fmt = M.formatTime(remaining)
                    safeSet(timerLabel, string.format("남은 시간: %s", fmt))
                    safeSet(lSession, string.format("세션 시간: %s", fmt))
                    task.wait(1); remaining = remaining - 1
                end
                safeSet(timerLabel, "세션이 만료되었습니다.")
                safeSet(lSession, "세션 시간: 만료됨")
                _G.COMBOWICK_ACTIVE = false
                pcall(function() Library:Unload() end)
                task.wait(0.5)
                M.reloadExist()
            end)
            local scriptUrl = M.getScriptForGame(token)
            if M.loadFreeScript(scriptUrl, token) then task.wait(2); pcall(function() Library:Unload() end) end
        end

    elseif result.status == "cooldown" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "대기 중")
        safeSet(hintLabel, "11시간 키를 받거나, 대기 시간이 끝날 때까지 기다리세요.")
        Library:Notify({Title="COMBOWICK", Description="대기 중입니다. 키를 받으면 대기를 건너뛸 수 있습니다.", Time=6})
        task.spawn(function()
            while remaining > 0 do
                local fmt = M.formatTime(remaining)
                safeSet(timerLabel, string.format("대기 시간: %s", fmt))
                safeSet(lCooldown, string.format("대기 시간: %s", fmt))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "대기 시간이 끝났습니다.")
            safeSet(lCooldown, "대기 시간: 완료")
            safeSet(hintLabel, "")
            Library:Notify({Title="COMBOWICK", Description="대기 시간이 끝났습니다. 다시 불러오는 중...", Time=3})
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "throttled" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "요청 과다")
        safeSet(hintLabel, "요청이 너무 많습니다. 잠시 기다려 주세요.")
        Library:Notify({Title="COMBOWICK", Description="요청이 너무 많습니다. 잠시만 기다려 주세요.", Time=5})
        task.spawn(function()
            while remaining > 0 do
                safeSet(timerLabel, string.format("%s 후 재시도", M.formatTime(remaining)))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "다시 불러오는 중...")
            safeSet(hintLabel, "")
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "disabled" then
        safeSet(statusLabel, "서비스 일시 중단")
        safeSet(hintLabel, "COMBOWICK가 일시적으로 오프라인 상태입니다.")
        Library:Notify({Title="COMBOWICK", Description="현재 서비스가 중단되었습니다. 나중에 다시 시도해 주세요.", Time=6})

    elseif result.status == "banned" then
        safeSet(statusLabel, "차단됨")
        Library:Notify({Title="COMBOWICK", Description="차단되었습니다.", Time=5})

    elseif result.status == "game_not_allowed" then
        safeSet(statusLabel, "🚫 지원되지 않는 게임")
        safeSet(hintLabel, "아직 지원되지 않는 게임입니다. 스크립트가 있는 경우 프리미엄 키는 계속 작동합니다.")
        Library:Notify({Title="COMBOWICK", Description="아직 지원되지 않는 게임입니다.", Time=6})

    else
        safeSet(statusLabel, "오류")
        safeSet(hintLabel, "서버에 연결할 수 없습니다. 스크립트를 다시 실행해 주세요.")
        Library:Notify({Title="COMBOWICK", Description=tostring(result.message or "알 수 없는 오류가 발생했습니다."), Time=5})
    end
end)

